function truncatePrompt(prompt: string, limit = 60): string {
  const trimmed = prompt.trim();
  if (!trimmed) {
    return 'No prompt';
  }
  if (trimmed.length <= limit) {
    return trimmed;
  }
  return `${trimmed.slice(0, limit - 1)}...`;
}

